#!/usr/bin/env node
/**
 * @file prepare-clean-types.mjs
 *
 * Regenerate WXT types as if no build artifacts existed under
 * extension/public/. CI sees that state on every checkout
 * because the generated files are gitignored, so running this
 * before `pnpm typecheck` locally produces the same result CI
 * will, regardless of whether `pnpm dev` or `pnpm build` has
 * already populated the artifact.
 *
 * WXT builds the `PublicPath` type by scanning extension/public/
 * at `wxt prepare` time. A literal like
 * `browser.runtime.getURL("/whats-new.json")` typechecks once
 * the build script has populated the file but fails on a fresh
 * checkout. The pre-push lefthook calls this script before
 * `pnpm -r typecheck` so a literal of that shape fails the
 * gate locally instead of waiting for CI to surface it.
 *
 * Removed artifacts are regenerated by the next `pnpm dev` or
 * `pnpm build` (both pipe through build-whats-new.mjs first),
 * so the working tree is not permanently affected.
 *
 * Keep GENERATED_PUBLIC_FILES aligned with the corresponding
 * `# Generated by ...` patterns in .gitignore.
 */

import { existsSync, unlinkSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";
import process from "node:process";

const __dirname = dirname(fileURLToPath(import.meta.url));
const EXTENSION_ROOT = resolve(__dirname, "..");

/** Gitignored artifacts under extension/public/ that should NOT
 *  influence the WXT-generated PublicPath type at typecheck time. */
const GENERATED_PUBLIC_FILES = ["public/whats-new.json"];

for (const rel of GENERATED_PUBLIC_FILES) {
  const abs = resolve(EXTENSION_ROOT, rel);
  if (existsSync(abs)) {
    unlinkSync(abs);
    process.stdout.write(`[prepare-clean-types] Removed ${rel}\n`);
  }
}

// Shell:true so the `wxt` bin resolves from node_modules/.bin the
// same way an npm/pnpm script would. No user input flows into the
// argument list — all values are hardcoded.
const result = spawnSync("wxt", ["prepare"], {
  cwd: EXTENSION_ROOT,
  stdio: "inherit",
  shell: true,
});

if (result.status === 0) {
  process.stdout.write(
    "[prepare-clean-types] Types regenerated against clean public/ (CI-equivalent state)\n",
  );
}

process.exit(result.status ?? 0);
